sys_script_include.script:
var IncentNowCopilotService = Class.create();
IncentNowCopilotService.prototype = {

    getUserProfileId: function(userId) {

        var profileGR = new GlideRecord("x_ctans_incentnow_user_profile");
        profileGR.addQuery("user", userId);
        profileGR.setLimit(1);
        profileGR.query();

        if (profileGR.next()) {
            return profileGR.getUniqueValue();
        }

        return userId;
    },

    getResponse: function(query, userId) {

        gs.info("IncentNow :: RAW QUERY RECEIVED = " + query);
        gs.info("IncentNow :: USER ID RECEIVED = " + userId);

        try {

            query = (query || "")
                .toString()
                .toLowerCase()
                .replace(/[^a-z0-9\s]/g, "")
                .replace(/\s+/g, " ")
                .trim();

            if (!query) {
                return "Please enter your question.";
            }

            var intent = this.classifyIntentUsingAI(query);

            gs.info("IncentNow :: FINAL DETECTED INTENT = " + intent);

            if (intent == "security_block") {

                gs.info("IncentNow :: SECURITY BLOCK TRIGGERED");

                return "⚠️ You can only view your own incentive data.";
            }

            if (intent == "unknown") {

                gs.info("IncentNow :: UNKNOWN QUERY → LEARNING REPOSITORY");

                return this.storeUnknownQuestion(
                    query,
                    userId,
                    "unknown"
                );
            }

            var router = new IncentNowIntentRouter();

            return router.executeIntent(
                intent,
                userId,
                query
            );

        } catch (ex) {

            gs.error("IncentNow :: Exception = " + ex.message);

            return "Unable to process your request at the moment.";
        }
    },

    classifyIntentUsingAI: function(question) {

        try {

            gs.info("IncentNow :: ENTERED classifyIntentUsingAI()");
            gs.info("IncentNow :: QUESTION = " + question);

            var query = (question || "")
                .toString()
                .toLowerCase()
                .replace(/[^a-z0-9\s]/g, " ")
                .replace(/\s+/g, " ")
                .trim();

            if (!query) {
                return "unknown";
            }

            if (
                query.indexOf("plan components") > -1 ||
                query.indexOf("what are my plan components") > -1 ||
                query.indexOf("show my plan components") > -1 ||
                query.indexOf("components of my plan") > -1 ||
                (query.indexOf("components") > -1 &&
                    (query.indexOf("plan") > -1 ||
                        query.indexOf("compensation") > -1 ||
                        query.indexOf("incentive") > -1))
            ) {
                gs.info("IncentNow :: HARDCODED MATCH = plan_components");
                return "plan_components";
            }

            if (
                query.indexOf("incentive statement") > -1 ||
                query.indexOf("commission statement") > -1 ||
                query.indexOf("earnings statement") > -1 ||
                query.indexOf("show my statement") > -1 ||
                query.indexOf("latest statement") > -1
            ) {

                gs.info(
                    "IncentNow :: HARDCODED MATCH = incentive_statement"
                );

                return "incentive_statement";
            }

            if (
                query === "plan" ||
                query === "my plan" ||
                query.indexOf("what is my plan") === 0 ||
                query.indexOf("show my plan") === 0
            ) {
                gs.info("IncentNow :: HARDCODED MATCH = plan");
                return "plan";
            }

            if (
                query.indexOf("ytd") > -1 ||
                query.indexOf("year to date") > -1
            ) {
                gs.info("IncentNow :: SAFE MATCH = ytd_payout");
                return "ytd_payout";
            }

            if (
                query.indexOf("qtd") > -1 ||
                query.indexOf("quarter to date") > -1
            ) {
                gs.info("IncentNow :: SAFE MATCH = qtd_payout");
                return "qtd_payout";
            }

            if (
                query.indexOf("monthly payout") > -1 ||
                query.indexOf("monthly payouts") > -1 ||
                query.indexOf("show my monthly payouts") > -1 ||
                query.indexOf("what are my monthly payouts") > -1 ||
                query.indexOf("month wise payout") > -1 ||
                query.indexOf("month wise payouts") > -1 ||
                query.indexOf("monthwise payout") > -1 ||
                query.indexOf("monthwise payouts") > -1
            ) {
                gs.info("IncentNow :: HARDCODED MATCH = monthly_payout");
                return "monthly_payout";
            }

            if (
                query.indexOf("breakdown") > -1 ||
                query.indexOf("payout breakdown") > -1 ||
                query.indexOf("commission breakdown") > -1 ||
                query.indexOf("earnings breakdown") > -1 ||
                query.indexOf("show my payout breakdown") > -1
            ) {
                gs.info("IncentNow :: HARDCODED MATCH = breakdown");
                return "breakdown";
            }

            if (
                query.indexOf("earning rules") > -1 ||
                query.indexOf("earning rule") > -1 ||
                query.indexOf("show my earning rules") > -1 ||
                query.indexOf("what are my earning rules") > -1
            ) {

                gs.info(
                    "IncentNow :: HARDCODED MATCH = earning_rules"
                );

                return "earning_rules";
            }
            if (
                query.indexOf("payout components") > -1 ||
                query.indexOf("show my payout components") > -1 ||
                query.indexOf("commission components") > -1 ||
                query.indexOf("earning components") > -1 ||
                query.indexOf("incentive components") > -1 ||
                query.indexOf("payout details by component") > -1 ||
                query.indexOf("commission split") > -1
            ) {

                gs.info(
                    "IncentNow :: HARDCODED MATCH = payout_components"
                );

                return "payout_components";
            }

            if (
                query.indexOf("payout summary") > -1 ||
                query.indexOf("show my payout summary") > -1 ||
                query.indexOf("summary") > -1
            ) {
                gs.info("IncentNow :: HARDCODED MATCH = summary");
                return "summary";
            }

            if (
                query.indexOf("explain") > -1 &&
                (
                    query.indexOf("payout") > -1 ||
                    query.indexOf("commission") > -1 ||
                    query.indexOf("earnings") > -1 ||
                    query.indexOf("incentive") > -1
                )
            ) {

                gs.info(
                    "IncentNow :: HARDCODED MATCH = ai_explanation"
                );

                return "ai_explanation";
            }

            if (
                query.indexOf("payout") > -1 ||
                query.indexOf("my payout") > -1 ||
                query.indexOf("latest payout") > -1 ||
                query.indexOf("total payout") > -1
            ) {
                gs.info("IncentNow :: HARDCODED MATCH = payout");
                return "payout";
            }
            if (
                query === "bu" ||
                query.indexOf("business unit") > -1 ||
                query.indexOf("my bu") > -1
            ) {
                gs.info("IncentNow :: HARDCODED MATCH = business_unit");
                return "business_unit";
            }

            var configGR = new GlideRecord("x_ctans_incentnow_ai_intent_configuration");
            configGR.addQuery("active", true);
            configGR.addNotNullQuery("keywords");
            configGR.orderByDesc("priority");
            configGR.query();

            while (configGR.next()) {

                var intentName = (configGR.getValue("intent_name") || "")
                    .toLowerCase()
                    .trim();

                var keywords = (configGR.getValue("keywords") || "")
                    .toLowerCase()
                    .trim();

                if (!keywords) {
                    continue;
                }

                var keywordList = keywords.split(",");

                for (var i = 0; i < keywordList.length; i++) {

                    var keyword = (keywordList[i] || "")
                        .toLowerCase()
                        .trim();

                    if (!keyword) {
                        continue;
                    }

                    if (query.indexOf(keyword) > -1) {

                        gs.info(
                            "IncentNow :: CONFIG MATCH FOUND = " +
                            intentName +
                            " using keyword = " +
                            keyword
                        );

                        return intentName;
                    }
                }
            }

            gs.info("IncentNow :: No config match found");

            return "unknown";

        } catch (ex) {

            gs.error(
                "IncentNow :: classifyIntentUsingAI Error = " +
                ex
            );

            return "unknown";
        }
    },

    normalizeMonth: function(text) {

        if (!text)
            return "";

        var map = {
            jan: "january",
            january: "january",

            feb: "february",
            february: "february",

            mar: "march",
            march: "march",

            apr: "april",
            april: "april",

            may: "may",

            jun: "june",
            june: "june",

            jul: "july",
            july: "july",

            aug: "august",
            august: "august",

            sep: "september",
            sept: "september",
            september: "september",

            oct: "october",
            october: "october",

            nov: "november",
            november: "november",

            dec: "december",
            december: "december"
        };

        text = (text || "")
            .toString()
            .toLowerCase()
            .replace(/[^a-z0-9\s]/g, " ")
            .replace(/\s+/g, " ")
            .trim();

        for (var key in map) {
            var reg = new RegExp("\\b" + key + "\\b", "g");
            text = text.replace(reg, map[key]);
        }

        text = text
            .replace(/\s+/g, " ")
            .trim();

        gs.info("IncentNow :: NORMALIZED MONTH TEXT = " + text);

        return text;
    },

    extractMonthYear: function(query) {

        query = this.normalizeMonth(query || "");

        var months = [
            "january", "february", "march", "april",
            "may", "june", "july", "august",
            "september", "october", "november", "december"
        ];

        var month = "";
        var year = "";

        for (var i = 0; i < months.length; i++) {
            if (query.indexOf(months[i]) > -1) {
                month = months[i];
                break;
            }
        }

        var yearMatch = query.match(/\b(20\d{2})\b/);

        if (yearMatch)
            year = yearMatch[0];

        gs.info("IncentNow :: EXTRACTED MONTH = " + month);
        gs.info("IncentNow :: EXTRACTED YEAR = " + year);

        if (month && year)
            return month + " " + year;

        if (month)
            return month;

        if (year)
            return year;

        return "";
    },

    normalizeQuestion: function(question) {

        if (!question) {
            return "";
        }

        var normalized = question.toString().toLowerCase();

        normalized = normalized.replace(/\s+/g, " ");
        normalized = normalized.replace(/[^\w\s]/gi, "");
        normalized = normalized.trim();

        return normalized;
    },

    storeUnknownQuestion: function(question, userId, detectedIntent) {

        try {

            var normalizedQuestion = this.normalizeQuestion(question);

            var existingGR = new GlideRecord("x_ctans_incentnow_ai_learning_repository");
            existingGR.addQuery("normalized_question", normalizedQuestion);
            existingGR.query();

            if (existingGR.next()) {

                var currentCount =
                    parseInt(existingGR.getValue("frequency_count"), 10) || 0;

                existingGR.setValue(
                    "frequency_count",
                    currentCount + 1
                );

                existingGR.setValue(
                    "last_asked",
                    new GlideDateTime()
                );

                existingGR.update();

                gs.info(
                    "IncentNow :: Existing learning record updated = " +
                    question
                );

                return "Your request has been captured for improvement. Our team is enhancing IncentNow Copilot for this scenario.";
            }

            var learnGR = new GlideRecord("x_ctans_incentnow_ai_learning_repository");
            learnGR.initialize();

            learnGR.setValue("question", question);
            learnGR.setValue(
                "normalized_question",
                normalizedQuestion
            );

            if (detectedIntent) {
                learnGR.setValue(
                    "detected_intent",
                    detectedIntent
                );
            }

            learnGR.setValue("status", "New");
            learnGR.setValue("frequency_count", 1);
            learnGR.setValue(
                "last_asked",
                new GlideDateTime()
            );
            learnGR.setValue("source_channel", "Portal");

            learnGR.insert();

            gs.info(
                "IncentNow :: Learning record created for question = " +
                question
            );

            return "Your request has been captured for improvement. Our team is enhancing IncentNow Copilot for this scenario.";

        } catch (ex) {

            gs.error("========== SELF LEARNING ERROR START ==========");
            gs.error("Question = " + question);
            gs.error("UserId = " + userId);
            gs.error("Detected Intent = " + detectedIntent);
            gs.error("Exception = " + ex);
            gs.error("Exception Message = " + ex.message);
            gs.error("========== SELF LEARNING ERROR END ==========");

            return "We could not process your request at the moment. Please try again later.";
        }
    },

    handleQuotaAttainment: function(userId) {

        try {

            var profileId = this.getUserProfileId(userId);

            var stmtGR = new GlideRecord(
                "x_ctans_incentnow_incentive_statement"
            );

            stmtGR.addQuery("user", profileId);
            stmtGR.orderByDesc("sys_created_on");
            stmtGR.setLimit(1);
            stmtGR.query();

            if (!stmtGR.next()) {
                return "📈 Your quota attainment is 0.00%";
            }

            var attainment = parseFloat(
                stmtGR.getValue("quota_attainment")
            );

            if (isNaN(attainment)) {
                attainment = 0;
            }

            return "📈 Your quota attainment is " +
                attainment.toFixed(2) + "%";

        } catch (ex) {

            gs.error(
                "IntentRouter :: handleQuotaAttainment Error = " +
                ex.message
            );

            return "Unable to retrieve quota attainment details at the moment.";
        }
    },

    handleYTDPayout: function(userId) {

        try {

            var profileId = this.getUserProfileId(userId);

            var metricGR = new GlideRecord("x_ctans_incentnow_metric_report");

            metricGR.addQuery("user", profileId);
            metricGR.addQuery("period_type", "month");
            metricGR.query();

            var totalCommission = 0;

            while (metricGR.next()) {
                totalCommission += parseFloat(
                    metricGR.getValue("total_commission") || 0
                );
            }

            gs.info(
                "IntentRouter :: YTD Commission Calculated = " +
                totalCommission +
                " | Profile = " +
                profileId
            );

            return "Your Year-to-Date (YTD) commission is $" +
                totalCommission.toFixed(2);

        } catch (ex) {

            gs.error(
                "IntentRouter :: Error in handleYTDPayout() :: " +
                ex.message
            );

            return "Unable to retrieve your Year-to-Date commission at this time.";
        }
    },

    handleMonthlyPayout: function(userId) {

        try {

            var profileId = this.getUserProfileId(userId);

            var gr = new GlideRecord(
                "x_ctans_incentnow_payout_results"
            );

            var qc = gr.addQuery("user", userId);
            qc.addOrCondition("user", profileId);

            gr.orderBy("fiscal_period");
            gr.query();

            if (!gr.next()) {
                return "No monthly payout data available.";
            }

            var monthlyData = {};
            var totalPayout = 0;

            do {

                var fiscalPeriod =
                    gr.getDisplayValue("fiscal_period") ||
                    "Unknown Period";

                var payoutValue =
                    parseFloat(
                        gr.getValue("payout_value")
                    ) || 0;

                if (!monthlyData[fiscalPeriod]) {
                    monthlyData[fiscalPeriod] = 0;
                }

                monthlyData[fiscalPeriod] += payoutValue;
                totalPayout += payoutValue;

            } while (gr.next());

            var months = [];

            for (var month in monthlyData) {
                months.push(month);
            }

            var monthOrder = {
                "January": 1,
                "February": 2,
                "March": 3,
                "April": 4,
                "May": 5,
                "June": 6,
                "July": 7,
                "August": 8,
                "September": 9,
                "October": 10,
                "November": 11,
                "December": 12
            };

            months.sort(function(a, b) {

                var aParts = a.split(" ");
                var bParts = b.split(" ");

                var aYear = parseInt(aParts[1], 10);
                var bYear = parseInt(bParts[1], 10);

                if (aYear !== bYear) {
                    return aYear - bYear;
                }

                return monthOrder[aParts[0]] -
                    monthOrder[bParts[0]];
            });

            var response =
                "📊 Here are your monthly payouts:\n\n";

            for (var i = 0; i < months.length; i++) {

                var month = months[i];

                response +=
                    "• " +
                    month +
                    ": $" +
                    monthlyData[month].toLocaleString(
                        "en-US", {
                            minimumFractionDigits: 2,
                            maximumFractionDigits: 2
                        }
                    ) +
                    "\n";
            }

            response +=
                "\n——————————————\n" +
                "💰 Total Monthly Payout: $" +
                totalPayout.toLocaleString(
                    "en-US", {
                        minimumFractionDigits: 2,
                        maximumFractionDigits: 2
                    }
                );

            return response;

        } catch (ex) {

            gs.error(
                "IntentRouter :: handleMonthlyPayout Error = " +
                ex.message
            );

            return "Unable to fetch monthly payout details at the moment.";
        }
    },

    //Handlelookup
    // handleLookupRules: function(userId) {

    //     gs.error("LOOKUP_DEBUG :: ENTERED");

    //     return "ASHOK_LOOKUP_TEST_123456789";
    // },



    handleQTDPayout: function(userId) {

        gs.error("QTD_DEBUG :: START");

        try {

            var profileId = this.getUserProfileId(userId);

            gs.error("QTD_DEBUG :: PROFILE = " + profileId);

            var gr = new GlideRecord("x_ctans_incentnow_metric_report");

            gr.addQuery("user", profileId);
            gr.addQuery("period_type", "month");
            gr.orderByDesc("sys_created_on");
            gr.query();

            gs.error("QTD_DEBUG :: COUNT = " + gr.getRowCount());

            var totalCommission = 0;
            var recordCount = 0;
            var periods = [];

            while (gr.next()) {

                var commission =
                    parseFloat(gr.getValue("total_commission")) || 0;

                totalCommission += commission;
                recordCount++;

                periods.push(
                    gr.getDisplayValue("fiscal_period")
                );

                gs.error(
                    "QTD_DEBUG :: RECORD = " +
                    gr.getValue("number") +
                    " | COMMISSION = " +
                    commission
                );
            }

            gs.error(
                "QTD_DEBUG :: TOTAL = " +
                totalCommission
            );

            if (recordCount === 0) {

                return "No QTD commission data found.";
            }

            return "Your QTD commission is $" +
                totalCommission.toFixed(2);

        } catch (ex) {

            gs.error(
                "QTD_DEBUG :: ERROR = " +
                ex.message
            );

            return "Unable to retrieve QTD commission details.";
        }
    },

    _getMonthOrder: function(text) {

        var months = [
            "january", "february", "march",
            "april", "may", "june",
            "july", "august", "september",
            "october", "november", "december"
        ];

        for (var i = 0; i < months.length; i++) {
            if (text.indexOf(months[i]) > -1) {
                return i;
            }
        }

        return -1;
    },

    _getQuarterFromMonthIndex: function(index) {

        if (index <= 2) return "Q1";
        if (index <= 5) return "Q2";
        if (index <= 8) return "Q3";
        return "Q4";
    },

    handlePayout: function(userId, query) {

        gs.info("IntentRouter :: ENTERED handlePayout()");
        gs.info("IntentRouter :: USER = " + userId);
        gs.info("IntentRouter :: QUERY = " + query);

        try {

            var profileId = this.getUserProfileId(userId);

            gs.info("IntentRouter :: PROFILE = " + profileId);

            var periodFromQuery = this.extractMonthYear(query || "");

            gs.info(
                "IntentRouter :: EXTRACTED PERIOD = " +
                periodFromQuery
            );

            var stmtGR = new GlideRecord(
                "x_ctans_incentnow_incentive_statement"
            );

            stmtGR.addQuery("user", profileId);
            stmtGR.orderByDesc("sys_created_on");
            stmtGR.query();

            var fallback = null;

            while (stmtGR.next()) {

                var fiscalPeriod =
                    stmtGR.getDisplayValue("fiscal_period") || "";

                var normalizedPeriod =
                    this.normalizeMonth(fiscalPeriod);

                var payout =
                    parseFloat(
                        stmtGR.getValue("total_commission")
                    ) || 0;

                // Exact Month/Year Match
                if (periodFromQuery) {

                    var normalizedQuery =
                        this.normalizeMonth(periodFromQuery);

                    if (
                        normalizedPeriod === normalizedQuery ||
                        normalizedPeriod.indexOf(normalizedQuery) > -1
                    ) {

                        return "💰 Your payout for " +
                            fiscalPeriod +
                            " is $" +
                            payout.toLocaleString(
                                "en-US", {
                                    minimumFractionDigits: 2,
                                    maximumFractionDigits: 2
                                }
                            );
                    }
                }

                // Latest record fallback
                if (!fallback) {

                    fallback = {
                        period: fiscalPeriod,
                        payout: payout
                    };
                }
            }

            // User requested specific month but none found
            if (periodFromQuery) {

                return "No payout data available for " +
                    periodFromQuery + ".";
            }

            // Latest payout
            if (fallback) {

                return "💰 Your payout for " +
                    fallback.period +
                    " is $" +
                    fallback.payout.toLocaleString(
                        "en-US", {
                            minimumFractionDigits: 2,
                            maximumFractionDigits: 2
                        }
                    );
            }

            return "No payout data available.";

        } catch (ex) {

            gs.error(
                "IntentRouter :: handlePayout Error = " +
                ex.message
            );

            return "Unable to fetch payout details at this time.";
        }
    },

    getMonthOrder: function(period) {

        period = (period || "").toLowerCase();

        if (period.indexOf("january") > -1) return 1;
        if (period.indexOf("february") > -1) return 2;
        if (period.indexOf("march") > -1) return 3;
        if (period.indexOf("april") > -1) return 4;
        if (period.indexOf("may") > -1) return 5;
        if (period.indexOf("june") > -1) return 6;
        if (period.indexOf("july") > -1) return 7;
        if (period.indexOf("august") > -1) return 8;
        if (period.indexOf("september") > -1) return 9;
        if (period.indexOf("october") > -1) return 10;
        if (period.indexOf("november") > -1) return 11;
        if (period.indexOf("december") > -1) return 12;

        return 99;
    },

    handleQuota: function(userId, query) {

        var profileId = this.getUserProfileId(userId);

        gs.info("QUOTA_DEBUG :: USER ID = " + userId);
        gs.info("QUOTA_DEBUG :: PROFILE ID = " + profileId);

        gs.info("IncentNow :: ENTERED handleQuota()");

        var originalQuery = query || "";
        var periodFromQuery = this.extractMonthYear(originalQuery);

        gs.info("IncentNow :: EXTRACTED PERIOD = " + periodFromQuery);

        query = (query || "").toLowerCase();

        /*
        =====================================================
        NEW USE CASE FLAGS
        =====================================================
        */

        var isMonthlyQuotaQuery =
            query.includes("monthly quota") ||
            query.includes("month wise quota") ||
            query.includes("monthwise quota") ||
            query.includes("show monthly quota") ||
            query.includes("what is my monthly quota") ||
            query.includes("my monthly quota");

        var isQuarterQuotaQuery =
            query.includes("quarter quota") ||
            query.includes("quota for quarter") ||
            query.includes("quarterly quota") ||
            query.includes("quarter quota details") ||
            query.includes("current quarter") ||
            query.includes("this quarter") ||
            query.includes("my quarter quota") ||
            query.includes("quota for current quarter") ||
            query.includes("what is my quota for quarter") ||
            query.includes("q1") ||
            query.includes("q2") ||
            query.includes("q3") ||
            query.includes("q4") ||
            query.includes("quarter 1") ||
            query.includes("quarter 2") ||
            query.includes("quarter 3") ||
            query.includes("quarter 4");

        var isQuotaAttainmentQuery =
            query.includes("quota attainment") ||
            query.includes("quota achievement") ||
            query.includes("quota achievement percentage") ||
            query.includes("attainment percentage") ||
            query.includes("achievement percentage");

        var isMonthYearQuery = false;
        var isMonthOnlyQuery = false;
        var isYearOnlyQuery = false;

        /*
        =====================================================
        VERY IMPORTANT PORTAL FIX
        Prevent "monthly quota" from being treated as month query
        =====================================================
        */

        if (!isMonthlyQuotaQuery) {

            if (
                periodFromQuery &&
                periodFromQuery.indexOf(" ") > -1 &&
                periodFromQuery.match(/\b20\d{2}\b/)
            ) {
                isMonthYearQuery = true;
            } else if (
                periodFromQuery &&
                !periodFromQuery.match(/\b20\d{2}\b/)
            ) {
                isMonthOnlyQuery = true;
            } else if (
                periodFromQuery &&
                periodFromQuery.match(/^\d{4}$/)
            ) {
                isYearOnlyQuery = true;
            }
        }

        /*
        =====================================================
        EXISTING LOGIC
        Get User Quota Assignment
        =====================================================
        */

        var assignGR = new GlideRecord("x_ctans_incentnow_user_quota_assignment");
        assignGR.addQuery("user", profileId);
        assignGR.orderByDesc("sys_created_on");
        assignGR.setLimit(1);
        assignGR.query();

        if (!assignGR.next()) {
            gs.info("IncentNow :: No quota assignment found");
            return "No quota assigned.";
        }

        var quotaId = assignGR.getValue("quota");

        gs.info("IncentNow :: QUOTA ID = " + quotaId);

        if (!quotaId) {
            return "No quota assigned.";
        }

        /*
        =====================================================
        EXISTING LOGIC
        Get Yearly Quota
        =====================================================
        */

        var quotaGR = new GlideRecord("x_ctans_incentnow_quota");

        if (!quotaGR.get(quotaId)) {
            gs.info("IncentNow :: Quota record not found");
            return "Quota details not found.";
        }

        var yearlyQuota =
            parseFloat(quotaGR.getValue("target_value")) || 0;

        var fiscalYear =
            quotaGR.getDisplayValue("fiscal_year") ||
            quotaGR.getDisplayValue("fiscal_period") ||
            "FY 2026";

        gs.info("IncentNow :: YEARLY QUOTA = " + yearlyQuota);
        gs.info("IncentNow :: FISCAL YEAR = " + fiscalYear);

        /*
        =====================================================
        NEW USE CASE
        Quota Attainment
        =====================================================
        */

        if (isQuotaAttainmentQuery) {

            var stmtGR = new GlideRecord("x_ctans_incentnow_incentive_statement");
            stmtGR.addQuery("user", profileId);
            stmtGR.orderByDesc("sys_created_on");
            stmtGR.setLimit(1);
            stmtGR.query();

            if (stmtGR.next()) {

                var attainment =
                    parseFloat(stmtGR.getValue("quota_attainment")) || 0;

                if (attainment > 0) {
                    return "📈 Your quota attainment is " +
                        attainment.toLocaleString("en-IN") +
                        "%";
                }
            }

            return "Quota attainment details are not available.";
        }

        /*
        =====================================================
        MONTHLY QUOTA PERIOD RECORDS
        =====================================================
        */

        var qpGR = new GlideRecord("x_ctans_incentnow_quota_period");
        qpGR.addQuery("quota", quotaId);
        qpGR.addQuery("period_type", "month");
        qpGR.orderBy("parent_period");
        qpGR.query();

        var latestMonthMatch = null;
        var yearExists = false;

        var monthlyResponse = "";
        var firstParentPeriod = "";
        var latestQuarter = "";
        var quarterTotal = 0;

        var requestedQuarter = "";

        if (query.includes("q1") || query.includes("quarter 1")) {
            requestedQuarter = "Q1";
        } else if (query.includes("q2") || query.includes("quarter 2")) {
            requestedQuarter = "Q2";
        } else if (query.includes("q3") || query.includes("quarter 3")) {
            requestedQuarter = "Q3";
        } else if (query.includes("q4") || query.includes("quarter 4")) {
            requestedQuarter = "Q4";
        }

        var monthlyQuotaMap = {};

        while (qpGR.next()) {

            var period =
                qpGR.getDisplayValue("fiscal_period") || "";

            var parentPeriod =
                qpGR.getDisplayValue("parent_period") || "";

            if (!parentPeriod) {

                if (
                    period.indexOf("January") > -1 ||
                    period.indexOf("February") > -1 ||
                    period.indexOf("March") > -1
                ) {
                    parentPeriod = "Q1";
                } else if (
                    period.indexOf("April") > -1 ||
                    period.indexOf("May") > -1 ||
                    period.indexOf("June") > -1
                ) {
                    parentPeriod = "Q2";
                } else if (
                    period.indexOf("July") > -1 ||
                    period.indexOf("August") > -1 ||
                    period.indexOf("September") > -1
                ) {
                    parentPeriod = "Q3";
                } else {
                    parentPeriod = "Q4";
                }
            }

            var normalizedPeriod =
                this.normalizeMonth(period);

            var monthlyQuota =
                parseFloat(qpGR.getValue("target_value")) || 0;

            var monthOrder =
                this.getMonthOrder(period);

            gs.info("IncentNow :: CHECKING PERIOD = " + period);
            gs.info("IncentNow :: PARENT PERIOD = " + parentPeriod);
            gs.info("IncentNow :: MONTHLY VALUE = " + monthlyQuota);
            gs.info("IncentNow :: MONTH ORDER = " + monthOrder);

            if (!firstParentPeriod && parentPeriod) {
                firstParentPeriod = parentPeriod;
                latestQuarter = parentPeriod;
            }

            /*
            =====================================================
            MONTHLY QUOTA GROUPING
            =====================================================
            */

            if (isMonthlyQuotaQuery) {

                if (!monthlyQuotaMap[parentPeriod]) {
                    monthlyQuotaMap[parentPeriod] = [];
                }

                monthlyQuotaMap[parentPeriod].push({
                    period: period,
                    amount: monthlyQuota,
                    monthOrder: monthOrder
                });
            }

            /*
            =====================================================
            QUARTER QUOTA
            =====================================================
            */

            if (isQuarterQuotaQuery) {

                if (
                    requestedQuarter &&
                    parentPeriod.indexOf(requestedQuarter) > -1
                ) {
                    latestQuarter = parentPeriod;
                    quarterTotal += monthlyQuota;
                } else if (
                    !requestedQuarter &&
                    parentPeriod === firstParentPeriod
                ) {
                    latestQuarter = parentPeriod;
                    quarterTotal += monthlyQuota;
                }
            }

            /*
            =====================================================
            SPECIFIC MONTH + YEAR
            =====================================================
            */

            if (isMonthYearQuery) {

                var normalizedQuery =
                    this.normalizeMonth(periodFromQuery);

                if (
                    normalizedPeriod === normalizedQuery ||
                    normalizedPeriod.indexOf(normalizedQuery) > -1
                ) {
                    return "🎯 Your quota for " +
                        period +
                        " is $" +
                        monthlyQuota.toLocaleString("en-IN");
                }
            }

            /*
            =====================================================
            MONTH ONLY
            =====================================================
            */

            if (isMonthOnlyQuery) {

                if (
                    normalizedPeriod.indexOf(periodFromQuery) > -1 &&
                    !latestMonthMatch
                ) {
                    latestMonthMatch = {
                        period: period,
                        amount: monthlyQuota
                    };
                }
            }

            /*
            =====================================================
            YEAR ONLY
            =====================================================
            */

            if (isYearOnlyQuery) {
                if (period.indexOf(periodFromQuery) > -1) {
                    yearExists = true;
                }
            }
        }

        /*
        =====================================================
        FINAL BUILD
        Monthly Quota Response with Proper Month Order
        =====================================================
        */

        if (isMonthlyQuotaQuery) {

            for (var quarter in monthlyQuotaMap) {

                monthlyResponse +=
                    "🎯 " + quarter + ":\n\n";

                monthlyQuotaMap[quarter].sort(function(a, b) {
                    return a.monthOrder - b.monthOrder;
                });

                for (var i = 0; i < monthlyQuotaMap[quarter].length; i++) {

                    monthlyResponse +=
                        "• " +
                        monthlyQuotaMap[quarter][i].period +
                        " → $" +
                        monthlyQuotaMap[quarter][i].amount.toLocaleString("en-IN") +
                        "\n";
                }

                monthlyResponse += "\n";
            }

            if (monthlyResponse) {
                return monthlyResponse.trim();
            }
        }

        /*
        =====================================================
        QUARTER QUOTA RETURN
        =====================================================
        */

        /*
        =====================================================
        MONTH ONLY RETURN
        =====================================================
        */

        if (isMonthOnlyQuery && latestMonthMatch) {
            return "🎯 Your quota for " +
                latestMonthMatch.period +
                " is $" +
                latestMonthMatch.amount.toLocaleString("en-IN");
        }

        /*
        =====================================================
        MONTH NOT FOUND
        =====================================================
        */

        if (isMonthYearQuery || isMonthOnlyQuery) {
            return "Commission data is not yet available for the selected period. Please check again later.";
        }

        /*
        =====================================================
        YEAR QUERY
        =====================================================
        */

        if (isYearOnlyQuery) {

            if (yearExists || yearlyQuota > 0) {
                return "🎯 Your total yearly quota for " +
                    periodFromQuery +
                    " is $" +
                    yearlyQuota.toLocaleString("en-IN");
            }

            return "Commission data is not yet available for the selected period. Please check again later.";
        }

        /*
        =====================================================
        DEFAULT YEARLY QUOTA
        =====================================================
        */

        if (isQuarterQuotaQuery && quarterTotal > 0) {
            return "🎯 Your quota for " +
                latestQuarter +
                " is $" +
                quarterTotal.toLocaleString("en-IN");
        }

        if (yearlyQuota > 0) {
            return "🎯 Your total yearly quota for " +
                fiscalYear +
                " is $" +
                yearlyQuota.toLocaleString("en-IN");
        }

        return "Quota not found.";
    },

