    handleBreakdown: function(userId, question) {

        gs.info("IncentNow :: ENTERED handleBreakdown()");
        gs.info("IncentNow :: QUESTION = " + question);

        try {

            var profileId = this.getUserProfileId(userId);

            var query = (question || "").toLowerCase();
            var requestedMonth = "";
            var requestedYear = "";
            var quarterMonths = [];
            var fiscalPeriodIds = [];
            var displayPeriod = "";

            var months = [
                "january",
                "february",
                "march",
                "april",
                "may",
                "june",
                "july",
                "august",
                "september",
                "october",
                "november",
                "december"
            ];

            for (var i = 0; i < months.length; i++) {
                if (query.indexOf(months[i]) > -1) {
                    requestedMonth =
                        months[i].charAt(0).toUpperCase() +
                        months[i].slice(1);
                    break;
                }
            }

            var yearMatch = query.match(/\b(20\d{2})\b/);

            if (yearMatch) {
                requestedYear = yearMatch[0];
            } else {
                requestedYear = "2026";
            }

            if (
                query.indexOf("q1") > -1 ||
                query.indexOf("quarter 1") > -1
            ) {
                quarterMonths = ["January", "February", "March"];
                displayPeriod = "Q1 " + requestedYear;
            }

            if (
                query.indexOf("q2") > -1 ||
                query.indexOf("quarter 2") > -1
            ) {
                quarterMonths = ["April", "May", "June"];
                displayPeriod = "Q2 " + requestedYear;
            }

            if (
                query.indexOf("q3") > -1 ||
                query.indexOf("quarter 3") > -1
            ) {
                quarterMonths = ["July", "August", "September"];
                displayPeriod = "Q3 " + requestedYear;
            }

            if (
                query.indexOf("q4") > -1 ||
                query.indexOf("quarter 4") > -1
            ) {
                quarterMonths = ["October", "November", "December"];
                displayPeriod = "Q4 " + requestedYear;
            }

            if (
                query.indexOf("yearly") > -1 ||
                query.indexOf("year") > -1 ||
                query.indexOf("ytd") > -1
            ) {
                quarterMonths = [
                    "January", "February", "March",
                    "April", "May", "June",
                    "July", "August", "September",
                    "October", "November", "December"
                ];

                displayPeriod = "Year " + requestedYear;
            }

            if (requestedMonth && quarterMonths.length === 0) {

                displayPeriod = requestedMonth + " " + requestedYear;

                var singleMonthGR = new GlideRecord("x_ctans_incentnow_payout_results");
                singleMonthGR.addQuery("user", profileId);
                singleMonthGR.query();

                while (singleMonthGR.next()) {

                    var fpDisplay =
                        singleMonthGR.getDisplayValue("fiscal_period") || "";

                    if (
                        fpDisplay.toLowerCase() ===
                        displayPeriod.toLowerCase()
                    ) {
                        fiscalPeriodIds.push(
                            singleMonthGR.getValue("fiscal_period")
                        );
                        break;
                    }
                }
            }

            if (quarterMonths.length > 0) {

                var periodGR = new GlideRecord("x_ctans_incentnow_payout_results");
                periodGR.addQuery("user", profileId);
                periodGR.query();

                while (periodGR.next()) {

                    var quarterDisplay =
                        periodGR.getDisplayValue("fiscal_period") || "";

                    for (var j = 0; j < quarterMonths.length; j++) {

                        if (
                            quarterDisplay.indexOf(quarterMonths[j]) > -1 &&
                            quarterDisplay.indexOf(requestedYear) > -1
                        ) {
                            var fpId =
                                periodGR.getValue("fiscal_period");

                            if (
                                fiscalPeriodIds.indexOf(fpId) === -1
                            ) {
                                fiscalPeriodIds.push(fpId);
                            }

                            break;
                        }
                    }
                }
            }

            if (
                !requestedMonth &&
                quarterMonths.length === 0 &&
                fiscalPeriodIds.length === 0
            ) {

                var latestGR = new GlideRecord("x_ctans_incentnow_payout_results");
                latestGR.addQuery("user", profileId);
                latestGR.orderByDesc("fiscal_period");
                latestGR.setLimit(1);
                latestGR.query();

                if (latestGR.next()) {

                    fiscalPeriodIds.push(
                        latestGR.getValue("fiscal_period")
                    );

                    displayPeriod =
                        latestGR.getDisplayValue("fiscal_period");
                }
            }

            if (fiscalPeriodIds.length === 0) {
                return "No payout breakdown available for the requested period.";
            }

            var gr = new GlideRecord("x_ctans_incentnow_payout_results");
            gr.addQuery("user", profileId);
            gr.addQuery(
                "fiscal_period",
                "IN",
                fiscalPeriodIds.join(",")
            );
            gr.orderBy("step_number");
            gr.query();

            if (!gr.hasNext()) {
                return "No payout breakdown available for " + displayPeriod + ".";
            }

            var groupedData = {};
            var totalPayout = 0;

            while (gr.next()) {

                var payoutRule =
                    gr.getDisplayValue("payout_summary_rule") || "";

                var formula =
                    gr.getValue("formula") || "";

                var payoutValue =
                    parseFloat(gr.getValue("payout_value")) || 0;

                if (!groupedData[payoutRule]) {
                    groupedData[payoutRule] = {
                        total: 0,
                        formulas: []
                    };
                }

                groupedData[payoutRule].total += payoutValue;

                if (formula) {
                    groupedData[payoutRule].formulas.push(formula);
                }

                totalPayout += payoutValue;
            }

            var response =
                "📊 Your payout breakdown for " +
                displayPeriod +
                " is as follows:\n\n";

            for (var rule in groupedData) {

                response += "• " + rule + "\n";

                if (groupedData[rule].formulas.length > 0) {
                    response +=
                        "Formula Summary: " +
                        groupedData[rule].formulas.join(" + ") +
                        "\n";
                }

                response +=
                    "Final Payable Amount: $" +
                    groupedData[rule].total.toLocaleString("en-IN") +
                    "\n\n";
            }

            response += "——————————————\n";
            response +=
                "💰 Total Breakdown Amount: $" +
                totalPayout.toLocaleString("en-IN");

            gs.info(
                "BREAKDOWN_DEBUG :: RESPONSE = \n" +
                response
            );

            return response;

        } catch (ex) {

            gs.error(
                "IncentNow :: handleBreakdown Error = " + ex
            );

            return "Unable to fetch payout breakdown details at the moment.";
        }
    },

    handleSummary: function(userId) {

        gs.info("IncentNow :: ENTERED handleSummary()");
        gs.info("IncentNow :: handleSummary USER = " + userId);

        var profileId = this.getUserProfileId(userId);

        gs.info("SUMMARY_DEBUG :: PROFILE ID = " + profileId);
        gs.info("SUMMARY_DEBUG :: USER ID = " + userId);

        var pu = new GlideRecord("x_ctans_incentnow_plan_users");
        pu.addQuery("x_ctans_incentnow_sales_user", profileId);
        pu.setLimit(1);
        pu.query();

        if (!pu.next()) {

            gs.info(
                "IncentNow :: No plan assigned for profile = " +
                profileId
            );

            return "No compensation plan assigned.";
        }

        var planId = pu.getValue(
            "x_ctans_incentnow_plan"
        );

        gs.info(
            "IncentNow :: PLAN ID = " +
            planId
        );

        var ps = new GlideRecord(
            "x_ctans_incentnow_payout_summary"
        );

        ps.addQuery("plan", planId);
        ps.orderBy("order");
        ps.query();

        var response =
            "📊 Payout Summary Details\n\n";

        var hasData = false;

        while (ps.next()) {

            hasData = true;

            var ruleName =
                ps.getValue("rule_name") || "";

            var operator =
                ps.getValue("operator") || "";

            var input1Earning =
                ps.getDisplayValue("input1_earning_rule") || "";

            var input1Lookup =
                ps.getDisplayValue("input1_id") || "";

            var input2Earning =
                ps.getDisplayValue("input2_earning_rule") || "";

            var input2Lookup =
                ps.getDisplayValue("input2_id") || "";

            gs.info(
                "SUMMARY_DEBUG :: RULE = " +
                ruleName
            );

            response +=
                "🔹 " + ruleName + "\n";

            var formulaParts = [];

            if (input1Earning) {
                formulaParts.push(input1Earning);
            }

            if (input1Lookup) {
                formulaParts.push(input1Lookup);
            }

            if (input2Earning) {
                formulaParts.push(input2Earning);
            }

            if (input2Lookup) {
                formulaParts.push(input2Lookup);
            }

            var operatorText = "";

            switch ((operator || "").toLowerCase()) {

                case "multiply":
                    operatorText = " × ";
                    break;

                case "add":
                    operatorText = " + ";
                    break;

                case "subtract":
                    operatorText = " - ";
                    break;

                case "divide":
                    operatorText = " ÷ ";
                    break;

                default:
                    operatorText = " " + operator + " ";
            }

            if (formulaParts.length > 0) {

                response +=
                    formulaParts.join(operatorText) +
                    "\n";
            }

            response += "\n";
        }

        if (!hasData) {

            gs.info(
                "IncentNow :: No payout summary records found"
            );

            return "No payout summary found for your compensation plan.";
        }

        gs.info(
            "SUMMARY_DEBUG :: RESPONSE = \n" +
            response
        );

        return response;
    },

