    handlePayoutComponents: function(userId) {

        try {

            gs.info("IncentNow :: ENTERED handlePayoutComponents()");
            gs.info("PAYOUT_COMPONENT_DEBUG :: USER ID = " + userId);

            var profileId = this.getUserProfileId(userId);

            gs.info(
                "PAYOUT_COMPONENT_DEBUG :: PROFILE ID = " +
                profileId
            );

            var stmtGR = new GlideRecord(
                "x_ctans_incentnow_incentive_statement"
            );

            stmtGR.addQuery("user", profileId);
            stmtGR.orderByDesc("sys_created_on");
            stmtGR.setLimit(1);
            stmtGR.query();

            if (!stmtGR.next()) {

                gs.info(
                    "PAYOUT_COMPONENT_DEBUG :: NO INCENTIVE STATEMENT FOUND"
                );

                return "No payout component details found for your profile.";
            }

            gs.info(
                "PAYOUT_COMPONENT_DEBUG :: STATEMENT SYS_ID = " +
                stmtGR.getUniqueValue()
            );

            gs.info(
                "PAYOUT_COMPONENT_DEBUG :: PERIOD = " +
                stmtGR.getDisplayValue("fiscal_period")
            );

            var fiscalPeriod =
                stmtGR.getDisplayValue("fiscal_period") || "";

            var totalCommission =
                stmtGR.getValue("total_commission") || "0";

            var payoutResults =
                stmtGR.getValue("payout_results") || "";

            var statementHTML =
                stmtGR.getValue("statement") || "";

            if (!payoutResults) {

                gs.info(
                    "PAYOUT_COMPONENT_DEBUG :: PAYOUT RESULTS EMPTY"
                );

                return "No payout components found for your latest incentive statement.";
            }

            var parsedResults = JSON.parse(payoutResults);

            if (!parsedResults || parsedResults.length === 0) {

                gs.info(
                    "PAYOUT_COMPONENT_DEBUG :: PARSED RESULTS EMPTY"
                );

                return "No payout components found for your latest incentive statement.";
            }

            var lookupMatches = [];
            var regex =
                /<div class="trace-lookup"><b>Lookup:<\/b>\s*(.*?)\s*→/g;

            var match;

            while ((match = regex.exec(statementHTML)) !== null) {

                lookupMatches.push(match[1]);
            }

            var lookupIndex = 0;

            var response = "";

            response +=
                "📊 Payout Components - " +
                fiscalPeriod +
                "\n\n";

            for (var i = 0; i < parsedResults.length; i++) {

                var item = parsedResults[i];

                var ruleName =
                    item.ruleName || "Payout Component";

                var payoutValue =
                    item.payoutValue || "0";

                var formula =
                    item.formula || "";

                gs.info(
                    "PAYOUT_COMPONENT_DEBUG :: RULE = " +
                    ruleName
                );

                response +=
                    "🔹 " +
                    ruleName +
                    "\n";

                if (item.trace && item.trace.length > 0) {

                    for (var t = 0; t < item.trace.length; t++) {

                        var trace = item.trace[t];

                        var traceType =
                            trace.type || "";

                        var traceName = "";

                        if (
                            typeof trace.name === "string"
                        ) {
                            traceName = trace.name;
                        }

                        var traceValue =
                            trace.value || "";

                        var traceOutput =
                            trace.output || "";

                        if (traceType == "earning") {

                            response +=
                                "Earning: ";

                            if (
                                traceName &&
                                traceValue
                            ) {

                                response +=
                                    traceName +
                                    " → " +
                                    traceValue +
                                    "\n";

                            } else if (traceName) {

                                response +=
                                    traceName +
                                    "\n";

                            } else {

                                response +=
                                    traceValue +
                                    "\n";
                            }
                        }

                        if (traceType == "lookup") {

                            var dynamicLookupName = "";

                            if (
                                lookupMatches[
                                    lookupIndex
                                ]
                            ) {

                                dynamicLookupName =
                                    lookupMatches[
                                        lookupIndex
                                    ];

                                lookupIndex++;
                            }

                            response +=
                                "Lookup: ";

                            if (
                                dynamicLookupName &&
                                traceOutput
                            ) {

                                response +=
                                    dynamicLookupName +
                                    " → " +
                                    traceOutput +
                                    "\n";

                            } else if (
                                traceOutput
                            ) {

                                response +=
                                    traceOutput +
                                    "\n";

                            } else {

                                response +=
                                    "Lookup value not available\n";
                            }
                        }

                        if (
                            traceType ==
                            "calculation" &&
                            trace.formula
                        ) {

                            response +=
                                "Calculation: " +
                                trace.formula;

                            if (
                                trace.result
                            ) {

                                response +=
                                    " = " +
                                    trace.result;
                            }

                            response +=
                                "\n";
                        }
                    }

                } else if (formula) {

                    response +=
                        "Calculation: " +
                        formula +
                        "\n";
                }

                response +=
                    "Commission: $" +
                    parseFloat(
                        payoutValue || 0
                    ).toLocaleString(
                        "en-IN"
                    ) +
                    "\n\n";
            }

            response +=
                "💰 Total Commission: $" +
                parseFloat(
                    totalCommission || 0
                ).toLocaleString(
                    "en-IN"
                );

            gs.info(
                "PAYOUT_COMPONENT_DEBUG :: RESPONSE = \n" +
                response
            );

            return response.trim();

        } catch (ex) {

            gs.error(
                "PAYOUT_COMPONENT_DEBUG :: ERROR = " +
                ex
            );

            return "Unable to retrieve payout component details at the moment.";
        }
    },

    handlePlanComponents: function(userId) {

        gs.info("IncentNow :: ENTERED handlePlanComponents()");
        gs.info("IncentNow :: USER = " + userId);

        var profileId = this.getUserProfileId(userId);

        gs.info(
            "PLAN_COMPONENTS :: PROFILE ID = " +
            profileId
        );

        /*
        =====================================================
        STEP 1: GET ASSIGNED PLAN
        =====================================================
        */

        var pu = new GlideRecord(
            "x_ctans_incentnow_plan_users"
        );

        pu.addQuery(
            "x_ctans_incentnow_sales_user",
            profileId
        );

        pu.setLimit(1);
        pu.query();

        if (!pu.next()) {

            gs.info(
                "PLAN_COMPONENTS :: NO PLAN ASSIGNED"
            );

            return "No compensation plan assigned.";
        }

        var planId =
            pu.getValue("x_ctans_incentnow_plan");

        var planName =
            pu.getDisplayValue(
                "x_ctans_incentnow_plan"
            );

        gs.info(
            "PLAN_COMPONENTS :: PLAN ID = " +
            planId
        );

        var response =
            "📄 Plan Components for " +
            planName +
            "\n\n";

        var hasData = false;

        /*
        =====================================================
        1. EARNING RULES
        =====================================================
        */

        var er = new GlideRecord(
            "x_ctans_incentnow_earning_rule"
        );

        er.addQuery("plan", planId);
        er.orderBy("order");
        er.query();

        if (er.hasNext()) {

            hasData = true;

            response +=
                "💰 Earning Rules\n\n";

            while (er.next()) {

                var ruleName =
                    er.getValue("rule_name") || "-";

                var sourceObject =
                    er.getDisplayValue(
                        "source_object"
                    ) || "-";

                // FIX ADDED
                var fieldName =
                    er.getDisplayValue(
                        "field"
                    ) || "-";

                var aggregation =
                    er.getValue(
                        "aggregation"
                    ) || "-";

                var earningLevel =
                    er.getValue(
                        "earning_level"
                    ) || "-";

                response +=
                    "• " + ruleName + "\n" +
                    "  Source: " + sourceObject + "\n" +
                    "  Field: " + fieldName + "\n" +
                    "  Aggregation: " + aggregation.toUpperCase() + "\n" +
                    "  Level: " + earningLevel + "\n\n";
            }
        }

        /*
        =====================================================
        2. LOOKUP RULES
        =====================================================
        */

        var lr = new GlideRecord(
            "x_ctans_incentnow_lookup_rule"
        );

        lr.addQuery("plan", planId);
        lr.orderBy("step_number");
        lr.query();

        if (lr.hasNext()) {

            hasData = true;

            response +=
                "⚙️ Lookup Rules\n\n";

            while (lr.next()) {

                var stepNumber =
                    lr.getValue(
                        "step_number"
                    ) || "-";

                var stepName =
                    lr.getDisplayValue(
                        "step_name"
                    ) || "Lookup Rule";

                var ruleType =
                    lr.getValue(
                        "rule_type"
                    ) || "-";

                var rateValue =
                    lr.getValue(
                        "rate_value"
                    ) || "";

                var rateUnit =
                    lr.getValue(
                        "rate_unit"
                    ) || "";

                response +=
                    "• Step " +
                    stepNumber +
                    ": " +
                    stepName +
                    "\n";

                response +=
                    "  Type: " +
                    ruleType +
                    "\n";

                if (rateValue) {

                    response +=
                        "  Rate: " +
                        rateValue;

                    if (
                        rateUnit ==
                        "percentage"
                    ) {
                        response += "%";
                    }

                    response += "\n";
                }

                response += "\n";
            }
        }

        /*
        =====================================================
        3. PAYOUT SUMMARIES
        =====================================================
        */

        var ps = new GlideRecord(
            "x_ctans_incentnow_payout_summary"
        );

        ps.addQuery("plan", planId);
        ps.orderBy("order");
        ps.query();

        if (ps.hasNext()) {

            hasData = true;

            response +=
                "📊 Payout Summaries\n\n";

            while (ps.next()) {

                var payoutRule =
                    ps.getValue(
                        "rule_name"
                    ) || "Payout Rule";

                var operator =
                    ps.getValue(
                        "operator"
                    ) || "-";

                var earningRule =
                    ps.getDisplayValue(
                        "input1_earning_rule"
                    ) || "";

                var lookupRule =
                    ps.getDisplayValue(
                        "input2_id"
                    ) || "";

                response +=
                    "• " +
                    payoutRule +
                    "\n";

                if (
                    earningRule ||
                    lookupRule
                ) {

                    response +=
                        "  Formula:\n";

                    response +=
                        "  " +
                        earningRule +
                        " × " +
                        lookupRule +
                        "\n";
                }

                response +=
                    "  Operator: " +
                    operator +
                    "\n\n";
            }
        }

        /*
        =====================================================
        4. PLAN USERS
        =====================================================
        */

        var users = new GlideRecord(
            "x_ctans_incentnow_plan_users"
        );

        users.addQuery(
            "x_ctans_incentnow_plan",
            planId
        );

        users.query();

        if (users.hasNext()) {

            hasData = true;

            response +=
                "👥 Assigned Users\n\n";

            while (users.next()) {

                response +=
                    "• " +
                    (
                        users.getDisplayValue(
                            "x_ctans_incentnow_sales_user"
                        ) || "User"
                    ) +
                    "\n";
            }

            response += "\n";
        }

        /*
        =====================================================
        FINAL RETURN
        =====================================================
        */

        if (!hasData) {

            gs.info(
                "PLAN_COMPONENTS :: NO DATA FOUND"
            );

            return "No plan components found for your compensation plan.";
        }

        gs.info(
            "PLAN_COMPONENTS :: RESPONSE = \n" +
            response
        );

        return response;
    },

    handlePlan: function(userId) {

        gs.info("IncentNow :: ENTERED handlePlan()");
        gs.info("IncentNow :: USER = " + userId);

        /*
        =====================================================
        STEP 1: GET USER PROFILE
        =====================================================
