        );

        gs.info(
            "PLAN_DEBUG :: PLAN NAME = " +
            planName
        );

        /*
        =====================================================
        FINAL RESPONSE
        =====================================================
        */

        return "The assigned plan for " +
            userName +
            " is " +
            planName +
            " within the " +
            businessUnit +
            " business unit.";
    },

