    handleIncentiveStatement: function(userId, query) {

        gs.info("IncentNow :: ENTERED handleIncentiveStatement()");
        gs.info("IncentNow :: Statement Query = " + query);
        gs.info("IncentNow :: USER = " + userId);

        var profileId = this.getUserProfileId(userId);

        gs.info(
            "STATEMENT_DEBUG :: PROFILE ID = " +
            profileId
        );

        var periodFromQuery =
            this.extractMonthYear(query) || "";

        gs.info(
            "IncentNow :: Extracted Statement Period = " +
            periodFromQuery
        );

        var isMonthYearQuery = false;
        var isMonthOnlyQuery = false;
        var isYearOnlyQuery = false;

        if (
            periodFromQuery &&
            periodFromQuery.indexOf(" ") > -1 &&
            periodFromQuery.match(/\b20\d{2}\b/)
        ) {

            isMonthYearQuery = true;

        } else if (
            periodFromQuery &&
            !periodFromQuery.match(/\b20\d{2}\b/)
        ) {

            isMonthOnlyQuery = true;

        } else if (
            periodFromQuery &&
            periodFromQuery.match(/^\d{4}$/)
        ) {

            isYearOnlyQuery = true;
        }

        var currentYear =
            parseInt(
                new GlideDateTime().getYearLocalTime(),
                10
            );

        var requestedYearMatch =
            periodFromQuery.match(/\b(20\d{2})\b/);

        if (requestedYearMatch) {

            var requestedYear =
                parseInt(
                    requestedYearMatch[0],
                    10
                );

            if (requestedYear > currentYear) {

                return "Commission data is not yet available for the selected period. Please check again later.";
            }
        }

        var stmtGR = new GlideRecord(
            "x_ctans_incentnow_incentive_statement"
        );

        stmtGR.addQuery(
            "user",
            profileId
        );

        stmtGR.orderByDesc("sys_created_on");
        stmtGR.query();

        var latestMonthMatch = null;
        var latestYearMatch = null;
        var fallback = null;

        while (stmtGR.next()) {

            var fiscalPeriod =
                stmtGR.getDisplayValue(
                    "fiscal_period"
                ) || "";

            var normalizedPeriod =
                this.normalizeMonth(
                    fiscalPeriod
                );

            var totalCommission =
                parseFloat(
                    stmtGR.getValue(
                        "total_commission"
                    )
                ) || 0;

            gs.info(
                "STATEMENT_DEBUG :: PERIOD = " +
                fiscalPeriod
            );

            if (isMonthYearQuery) {

                var normalizedQuery =
                    this.normalizeMonth(
                        periodFromQuery
                    );

                if (
                    normalizedPeriod === normalizedQuery ||
                    normalizedPeriod.indexOf(
                        normalizedQuery
                    ) > -1
                ) {

                    return "📄 Incentive Statement\n\n" +
                        "📅 Period: " +
                        fiscalPeriod +
                        "\n" +
                        "💰 Total Commission: $" +
                        totalCommission.toLocaleString("en-IN") +
                        "\n\nStatement available for the selected fiscal period.";
                }
            }

            if (isMonthOnlyQuery) {

                if (
                    normalizedPeriod.indexOf(
                        periodFromQuery.toLowerCase()
                    ) > -1 &&
                    !latestMonthMatch
                ) {

                    latestMonthMatch = {
                        period: fiscalPeriod,
                        amount: totalCommission
                    };
                }
            }

            if (isYearOnlyQuery) {

                if (
                    fiscalPeriod.indexOf(
                        periodFromQuery
                    ) > -1 &&
                    !latestYearMatch
                ) {

                    latestYearMatch = {
                        period: fiscalPeriod,
                        amount: totalCommission
                    };
                }
            }

            if (!fallback) {

                fallback = {
                    period: fiscalPeriod,
                    amount: totalCommission
                };
            }
        }

        if (
            isMonthOnlyQuery &&
            latestMonthMatch
        ) {

            return "📄 Incentive Statement\n\n" +
                "📅 Period: " +
                latestMonthMatch.period +
                "\n" +
                "💰 Total Commission: $" +
                latestMonthMatch.amount.toLocaleString("en-IN");
        }

        if (
            isYearOnlyQuery &&
            latestYearMatch
        ) {

            return "📄 Incentive Statement\n\n" +
                "📅 Period: " +
                latestYearMatch.period +
                "\n" +
                "💰 Total Commission: $" +
                latestYearMatch.amount.toLocaleString("en-IN");
        }

        if (
            isMonthYearQuery ||
            isMonthOnlyQuery ||
            isYearOnlyQuery
        ) {

            return "Commission data is not yet available for the selected period. Please check again later.";
        }

        if (fallback) {

            return "📄 Latest Incentive Statement\n\n" +
                "📅 Period: " +
                fallback.period +
                "\n" +
                "💰 Total Commission: $" +
                fallback.amount.toLocaleString("en-IN");
        }

        return "No incentive statement found.";
    },

    handleAIExplanation: function(userId, query) {

        gs.info("IncentNow :: ENTERED handleAIExplanation()");
        gs.info("IncentNow :: AI Explanation Query = " + query);
        gs.info("IncentNow :: USER = " + userId);

        var profileId = this.getUserProfileId(userId);

        gs.info(
            "AI_EXPLANATION :: PROFILE ID = " +
            profileId
        );

        var stmtGR = new GlideRecord(
            "x_ctans_incentnow_incentive_statement"
        );

        stmtGR.addQuery(
            "user",
            profileId
        );

        stmtGR.orderByDesc("sys_created_on");
        stmtGR.setLimit(1);
        stmtGR.query();

        if (!stmtGR.next()) {

            gs.info(
                "AI_EXPLANATION :: NO PAYOUT DATA FOUND"
            );

            return "No payout data available.";
        }

        var payout =
            parseFloat(
                stmtGR.getValue(
                    "total_commission"
                )
            ) || 0;

        var fiscalPeriod =
            stmtGR.getDisplayValue(
                "fiscal_period"
            ) || "";

        gs.info(
            "AI_EXPLANATION :: PAYOUT = " +
            payout
        );

        gs.info(
            "AI_EXPLANATION :: PERIOD = " +
            fiscalPeriod
        );

        var payoutLevel = "";

        if (payout < 5000) {

            payoutLevel = "LOW";

        } else if (payout < 20000) {

            payoutLevel = "MEDIUM";

        } else {

            payoutLevel = "HIGH";
        }

        var response =
            "Payout Context\n\n" +
            "Fiscal Period: " +
            fiscalPeriod +
            "\n" +
            "Current Commission: $" +
            payout.toLocaleString("en-IN") +
            "\n" +
            "Payout Level: " +
            payoutLevel +
            "\n" +
            "Evaluation Factors: quota attainment, earning rules, lookup rules, payout summaries, bonus thresholds, and sales performance.\n\n" +
            "Use this factual information to explain how the payout was determined.";

        return response;
    },


    type: 'IncentNowCopilotService'
};
